/**
 * @param {number[]} nums1
 * @param {number[]} nums0
 * @return {number}
 */
function solve(nums1, nums0) {
    const MOD = 10**9 + 7;
    const n = nums1.length;

    // We need a custom comparison function to sort the fragments.
    // For two fragments A (1s_A, 0s_A) and B (1s_B, 0s_B), 
    // A should come before B if the combined value of AB is greater than BA.
    // Value(AB) = (1s_A * 2^(0s_A + 0s_B)) + Value(A_suffix) * 2^(0s_B) + Value(B_prefix)
    // This is equivalent to comparing the numbers represented by the binary strings.

    // A binary string S1 is lexicographically greater than S2 if and only if 
    // the number it represents is greater.
    // When concatenating fragments, we want the resulting string to be lexicographically largest.

    // Let's define a representation for each fragment: [num1, num0]
    const fragments = [];
    for (let i = 0; i < n; i++) {
        fragments.push({
            num1: nums1[i],
            num0: nums0[i]
        });
    }

    // Custom sorting logic: Compare two fragments A and B.
    // A should come before B if AB > BA (lexicographically).
    // We construct the two potential concatenations as strings and compare them.
    fragments.sort((A, B) => {
        // String for AB: A's 1s + A's 0s + B's 1s + B's 0s
        const AB_str = '1'.repeat(A.num1) + '0'.repeat(A.num0) + 
                       '1'.repeat(B.num1) + '0'.repeat(B.num0);

        // String for BA: B's 1s + B's 0s + A's 1s + A's 0s
        const BA_str = '1'.repeat(B.num1) + '0'.repeat(B.num0) + 
                       '1'.repeat(A.num1) + '0'.repeat(A.num0);

        // We want descending order (largest first).
        // If AB_str > BA_str, A should come before B (return -1 for ascending sort logic)
        if (AB_str > BA_str) return -1;
        if (AB_str < BA_str) return 1;
        return 0;
    });

    let totalValue = 0n; // Use BigInt for intermediate calculation
    let currentPowerOf2 = 1n;

    // Iterate through the sorted fragments and calculate the total value modulo MOD
    for (let i = fragments.length - 1; i >= 0; i--) {
        const frag = fragments[i];
        const num1 = BigInt(frag.num1);
        const num0 = BigInt(frag.num0);
        const bigMOD = BigInt(MOD);

        // The current fragment contributes 2^num0 * (2^num1 - 1) to the total value
        // relative to the start of the string.
        // A simpler way is to calculate the value of the fragment and shift it.

        // The fragment is '1...1' (num1 times) followed by '0...0' (num0 times).
        // Its value is (2^num1 - 1) * 2^num0.

        // Since we are building the string from left to right (conceptually), 
        // and we are processing the sorted fragments in order (which corresponds to left to right),
        // we need to keep track of the total length accumulated so far to correctly place the new value.

        // Let's rethink the accumulation approach:
        // The total value is the sum of contributions from each fragment.
        // If the fragments are S_1, S_2, ..., S_k.
        // Value = Value(S_1) * 2^(L_2 + ... + L_k) + Value(S_2) * 2^(L_3 + ... + L_k) + ... + Value(S_k)

        // Since we sorted them correctly, we iterate forward (i = 0 to n-1)
        // and maintain the total accumulated length.
    }

    // Reset and iterate forward
    totalValue = 0n;
    let totalLength = 0;

    for (const frag of fragments) {
        const num1 = BigInt(frag.num1);
        const num0 = BigInt(frag.num0);
        const bigMOD = BigInt(MOD);

        // 1. Calculate the value of the current fragment (S_i)
        // Value(S_i) = (2^num1 - 1) * 2^num0

        // 2^num1 (mod MOD)
        let pow2_num1 = 1n;
        for (let j = 0; j < frag.num1; j++) {
            pow2_num1 = (pow2_num1 * 2n) % bigMOD;
        }

        // 2^num1 - 1 (mod MOD)
        let fragmentValue = (pow2_num1 - 1n + bigMOD) % bigMOD;

        // 2^num0 (mod MOD)
        let pow2_num0 = 1n;
        for (let j = 0; j < frag.num0; j++) {
            pow2_num0 = (pow2_num0 * 2n) % bigMOD;
        }

        // Value(S_i) = ((2^num1 - 1) * 2^num0) mod MOD
        fragmentValue = (fragmentValue * pow2_num0) % bigMOD;

        // 2. Determine the required shift for this fragment's value.
        // This fragment is followed by 'totalLength' bits from subsequent fragments.
        // We need to multiply fragmentValue by 2^totalLength (mod MOD).

        // 2^totalLength (mod MOD)
        let shiftFactor = 1n;
        for (let j = 0; j < totalLength; j++) {
            shiftFactor = (shiftFactor * 2n) % bigMOD;
        }

        // Contribution = (fragmentValue * 2^totalLength) mod MOD
        let contribution = (fragmentValue * shiftFactor) % bigMOD;

        // Update total value
        totalValue = (totalValue + contribution) % bigMOD;

        // Update total length for the next fragment
        totalLength += frag.num1 + frag.num0;
    }

    return Number(totalValue);
}

