import java.util.Arrays;
import java.util.Comparator;

public class Solution {
    public static long solve(long[] nums1, long[] nums0) {
        final long MOD = 1_000_000_007;
        int n = nums1.length;

        // Structure to hold fragment data
        class Fragment {
            int num1;
            int num0;

            Fragment(int num1, int num0) {
                this.num1 = num1;
                this.num0 = num0;
            }
        }

        Fragment[] fragments = new Fragment[n];
        for (int i = 0; i < n; i++) {
            fragments[i] = new Fragment((int) nums1[i], (int) nums0[i]);
        }

        // Custom sorting logic: A comes before B if AB > BA (lexicographically).
        Arrays.sort(fragments, new Comparator<Fragment>() {
            @Override
            public int compare(Fragment A, Fragment B) {
                // Construct AB string conceptually
                // AB: 1^A.num1 0^A.num0 1^B.num1 0^B.num0
                // BA: 1^B.num1 0^B.num0 1^A.num1 0^A.num0

                // Since we are dealing with large numbers, direct string comparison 
                // is the safest way to implement the comparison rule AB > BA.

                // For efficiency, we compare based on the numerical value derived from the comparison.
                // If AB > BA, A should come before B (return negative).
                // If AB < BA, A should come after B (return positive).

                // We will use BigInteger for safe comparison of the concatenated strings.

                String AB_str = "1".repeat(A.num1) + "0".repeat(A.num0) + 
                               "1".repeat(B.num1) + "0".repeat(B.num0);

                String BA_str = "1".repeat(B.num1) + "0".repeat(B.num0) + 
                               "1".repeat(A.num1) + "0".repeat(A.num0);

                // Lexicographical comparison in Java for strings
                int comparison = AB_str.compareTo(BA_str);

                // For descending order (largest first), if AB > BA (comparison > 0), 
                // we want A before B, so we return -1.
                return comparison > 0 ? -1 : (comparison < 0 ? 1 : 0);
            }
        });

        long totalValue = 0;
        long totalLength = 0;

        // Iterate forward over the sorted fragments (S1, S2, ..., Sk)
        // Value = Value(S1) * 2^(L2+...+Lk) + Value(S2) * 2^(L3+...+Lk) + ... + Value(Sk)
        for (int i = 0; i < n; i++) {
            Fragment frag = fragments[i];
            int num1 = frag.num1;
            int num0 = frag.num0;

            // 1. Calculate the value of the current fragment (S_i) modulo MOD
            // Value(S_i) = (2^num1 - 1) * 2^num0

            // Function to calculate (base^exp) % MOD
            java.util.function.BiFunction<Long, Integer, Long> power = 
                (base, exp) -> {
                long res = 1;
                long b = base % MOD;
                int e = exp;
                while (e > 0) {
                    if (e % 2 == 1) {
                        res = (res * b) % MOD;
                    }
                    b = (b * b) % MOD;
                    e /= 2;
                }
                return res;
            };

            // 2^num1 (mod MOD)
            long pow2_num1 = power.apply(2L, num1);

            // 2^num1 - 1 (mod MOD)
            long term1 = (pow2_num1 - 1 + MOD) % MOD;

            // 2^num0 (mod MOD)
            long term2 = power.apply(2L, num0);

            // Value(S_i) = (term1 * term2) mod MOD
            long fragmentValue = (term1 * term2) % MOD;

            // 2. Determine the required shift for this fragment's value.
            // This fragment is followed by 'totalLength' bits from subsequent fragments.
            // We need to multiply fragmentValue by 2^totalLength (mod MOD).

            // 2^totalLength (mod MOD)
            long shiftFactor = power.apply(2L, (int)totalLength);

            // Contribution = (fragmentValue * 2^totalLength) mod MOD
            long contribution = (fragmentValue * shiftFactor) % MOD;

            // Update total value
            totalValue = (totalValue + contribution) % MOD;

            // Update total length for the next fragment
            totalLength += num1 + num0;
        }

        return totalValue;
    }
}
